const loopNode = $('Loop Over Items').all();
const currentItem = loopNode[loopNode.length - 1];
const pageId = currentItem.json.id;

const props = currentItem.json.properties || {};
let pageTitle = null;
for (const key of Object.keys(props)) {
  const prop = props[key];
  if (prop.type === 'title' && prop.title && prop.title.length > 0) {
    pageTitle = prop.title.map(t => t.plain_text).join('').trim();
    break;
  }
}

// Brak tytułu = pusty rekord bazy, pomiń ale zwróć skip żeby pętla działała
if (!pageTitle) return [{ json: { skip: true, pageId, reason: 'no title' } }];

function simpleHash(str) {
  let hash = 0;
  for (let i = 0; i < str.length; i++) {
    hash = ((hash << 5) - hash) + str.charCodeAt(i);
    hash |= 0;
  }
  return Math.abs(hash);
}

const pageUrl = currentItem.json.url || '';
const rawInput = $input.item.json;
const blocks = Array.isArray(rawInput.results) ? rawInput.results : [];

// Brak bloków = pusta strona, pomiń ale zwróć skip
if (blocks.length === 0) return [{ json: { skip: true, pageId, reason: 'no blocks' } }];

let fullText = `# ${pageTitle}\n\n`;

for (const block of blocks) {
  const type = block.type;
  const content = block[type];

  if (content && content.rich_text && content.rich_text.length > 0) {
    const text = content.rich_text.map(t => t.plain_text).join('');
    if (text.trim()) {
      if (type === 'heading_1') fullText += `## ${text}\n`;
      else if (type === 'heading_2') fullText += `### ${text}\n`;
      else if (type === 'heading_3') fullText += `#### ${text}\n`;
      else fullText += text + '\n';
    }
  }

  if (type === 'table_row' && content && content.cells) {
    const rowText = content.cells
      .map(cell => cell.map(t => t.plain_text).join('').trim())
      .filter(c => c.length > 0)
      .join(' | ');
    if (rowText.trim()) fullText += rowText + '\n';
  }

  if (type === 'code' && content && content.rich_text) {
    const text = content.rich_text.map(t => t.plain_text).join('');
    if (text.trim()) fullText += `[kod] ${text}\n`;
  }
}

const textBody = fullText.trim();
if (textBody === `# ${pageTitle}`) return [{ json: { skip: true, pageId, reason: 'empty content' } }];

const chunkSize = 500;
const overlap = 50;
const chunks = [];
let start = 0;
while (start < textBody.length) {
  chunks.push(textBody.slice(start, start + chunkSize));
  start += chunkSize - overlap;
  if (start >= textBody.length) break;
}

return chunks.map((chunk, idx) => ({
  json: {
    skip: false,
    pageId,
    pageTitle,
    pageUrl,
    text: chunk,
    chunkIndex: idx,
    source: 'notion',
    indexedAt: new Date().toISOString(),
    pointId: simpleHash(`${pageId}_${idx}`)
  }
}));

const prev = $('Extract & Chunk Text').item.json;
const embedding = $input.item.json.embedding;

return [{
  json: {
    pointId: prev.pointId,
    pageId: prev.pageId,
    pageTitle: prev.pageTitle,
    pageUrl: prev.pageUrl,
    text: prev.text,
    chunkIndex: prev.chunkIndex,
    source: prev.source,
    indexedAt: prev.indexedAt,
    embedding
  }
}];
